--
-- Name: world_partition_detail; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.world_partition_detail AS
 SELECT p.id,
    p.partition_key,
    p.partition_stage,
    p.partition_seq,
    p.partition_type,
    p.map_name,
    p.display_name,
    p.summary,
    p.description,
    p.theme_code,
    p.group_key,
    p.group_seq,
    p.group_display_name,
    p.group_theme_code,
    p.landuse_code,
    p.dominant_landuse,
    p.persona_tag,
    p.texture_profile,
    p.is_road,
    p.is_walkable,
    p.area_m2,
    p.landuse_mix_score,
    p.centroid_lat,
    p.centroid_lng,
    p.city_name,
    p.district_name,
    p.dong_name,
    a.area_code AS admin_area_code,
    a.name_en AS dong_name_en,
    a.parent_id AS district_admin_id,
    p.gameplay_meta
   FROM (public.world_level_partition p
     JOIN public.world_admin_area a ON ((a.id = p.admin_area_id)));


